+pub struct LoRAPair {
+    /// Down projection matrix A: [dim][rank]
+    /// Stored as Vec<[f32; 2]> for rank-2
+    a: Vec<[f32; 2]>,
+    /// Up projection matrix B: [rank][dim]
+    /// Stored as [[f32; 256]; 2] for fixed 256-dim embeddings
+    b: [[f32; 256]; 2],
+    /// Scaling factor
+    alpha: f32,
+    /// Learning rate
+    lr: f32,
+    /// Embedding dimension
+    dim: usize,
+    /// Adaptation count for statistics
+    adapt_count: u64,
+}
