+        for i in 0..n {
+            low_rank[0] += input[i] * self.a[i][0];
+            low_rank[1] += input[i] * self.a[i][1];
+        }
+
+        // Compute delta = low_rank @ B (result: [dim])
+        // Output = input + alpha * delta
